const DiffTool = () => {
  const [left, setLeft] = React.useState('line one\nline two\nline three\ncommon line');
  const [right, setRight] = React.useState('line one\nmodified line\nline three\ncommon line\nnew line');
  const [diff, setDiff] = React.useState([]);

  const computeDiff = () => {
    const a = left.split('\n');
    const b = right.split('\n');
    const m = a.length, n = b.length;
    const dp = Array(m + 1).fill(null).map(() => Array(n + 1).fill(0));
    for (let i = 1; i <= m; i++) for (let j = 1; j <= n; j++) dp[i][j] = a[i-1] === b[j-1] ? dp[i-1][j-1] + 1 : Math.max(dp[i-1][j], dp[i][j-1]);
    const result = [];
    let i = m, j = n;
    while (i > 0 || j > 0) {
      if (i > 0 && j > 0 && a[i-1] === b[j-1]) {
        result.unshift({ type: 'same', left: a[i-1], right: b[j-1] });
        i--; j--;
      } else if (j > 0 && (i === 0 || dp[i][j-1] >= dp[i-1][j])) {
        result.unshift({ type: 'add', right: b[j-1] });
        j--;
      } else {
        result.unshift({ type: 'remove', left: a[i-1] });
        i--;
      }
    }
    setDiff(result);
  };

  React.useEffect(() => {
    computeDiff();
  }, [left, right]);

  const clear = () => {
    setLeft('');
    setRight('');
  };

  const typeStyle = (t) => {
    if (t === 'add') return { background: '#dcfce7' };
    if (t === 'remove') return { background: '#fee2e2' };
    return { background: '#f9fafb' };
  };
  const typeColor = (t) => {
    if (t === 'add') return '#16a34a';
    if (t === 'remove') return '#dc2626';
    return '#6b7280';
  };

  return React.createElement('div', { style: { fontFamily: 'system-ui, sans-serif', padding: '16px', display: 'flex', flexDirection: 'column', gap: '14px', height: '100%', overflow: 'auto' } },
    React.createElement('h3', { style: { margin: 0, fontSize: '16px', fontWeight: 600, color: '#111827' } }, 'Diff Tool'),
    React.createElement('div', { style: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px' } },
      React.createElement('div', null,
        React.createElement('div', { style: { fontSize: '11px', fontWeight: 600, color: '#6b7280', marginBottom: '4px' } }, 'Original'),
        React.createElement('textarea', {
          value: left,
          onChange: e => setLeft(e.target.value),
          placeholder: 'Original text...',
          style: { width: '100%', minHeight: '100px', fontSize: '12px', padding: '8px', borderRadius: '6px', border: '1px solid #d1d5db', resize: 'vertical', fontFamily: 'monospace', boxSizing: 'border-box' }
        })
      ),
      React.createElement('div', null,
        React.createElement('div', { style: { fontSize: '11px', fontWeight: 600, color: '#6b7280', marginBottom: '4px' } }, 'Modified'),
        React.createElement('textarea', {
          value: right,
          onChange: e => setRight(e.target.value),
          placeholder: 'Modified text...',
          style: { width: '100%', minHeight: '100px', fontSize: '12px', padding: '8px', borderRadius: '6px', border: '1px solid #d1d5db', resize: 'vertical', fontFamily: 'monospace', boxSizing: 'border-box' }
        })
      )
    ),
    React.createElement('div', { style: { display: 'flex', gap: '8px' } },
      React.createElement('button', { onClick: computeDiff, style: { fontSize: '12px', padding: '6px 14px', borderRadius: '4px', border: 'none', background: '#2563eb', color: '#fff', cursor: 'pointer', fontWeight: 600 } }, 'Compare'),
      React.createElement('button', { onClick: clear, style: { fontSize: '12px', padding: '6px 14px', borderRadius: '4px', border: 'none', background: '#6b7280', color: '#fff', cursor: 'pointer', fontWeight: 600 } }, 'Clear')
    ),
    React.createElement('div', null,
      React.createElement('div', { style: { fontSize: '11px', fontWeight: 600, color: '#6b7280', marginBottom: '4px' } }, 'Diff Output'),
      React.createElement('div', { style: { display: 'grid', gridTemplateColumns: '40px 1fr 1fr', gap: '0', border: '1px solid #e5e7eb', borderRadius: '6px', overflow: 'hidden' } },
        React.createElement('div', { style: { background: '#f3f4f6', padding: '6px 8px', fontSize: '10px', fontWeight: 700, color: '#6b7280', borderBottom: '1px solid #e5e7eb' } }, '#'),
        React.createElement('div', { style: { background: '#f3f4f6', padding: '6px 8px', fontSize: '10px', fontWeight: 700, color: '#6b7280', borderBottom: '1px solid #e5e7eb', borderLeft: '1px solid #e5e7eb' } }, 'Original'),
        React.createElement('div', { style: { background: '#f3f4f6', padding: '6px 8px', fontSize: '10px', fontWeight: 700, color: '#6b7280', borderBottom: '1px solid #e5e7eb', borderLeft: '1px solid #e5e7eb' } }, 'Modified'),
        diff.map((d, i) => React.createElement(React.Fragment, { key: i },
          React.createElement('div', { style: { ...typeStyle(d.type), padding: '5px 8px', fontSize: '11px', fontWeight: 700, color: typeColor(d.type), fontFamily: 'monospace', borderBottom: '1px solid #f3f4f6' } }, d.type === 'add' ? '+' : d.type === 'remove' ? '-' : ' '),
          React.createElement('div', { style: { ...typeStyle(d.type), padding: '5px 8px', fontSize: '12px', fontFamily: 'monospace', color: '#374151', borderLeft: '1px solid #f3f4f6', borderBottom: '1px solid #f3f4f6', whiteSpace: 'pre-wrap', wordBreak: 'break-all' } }, d.left || ''),
          React.createElement('div', { style: { ...typeStyle(d.type), padding: '5px 8px', fontSize: '12px', fontFamily: 'monospace', color: '#374151', borderLeft: '1px solid #f3f4f6', borderBottom: '1px solid #f3f4f6', whiteSpace: 'pre-wrap', wordBreak: 'break-all' } }, d.right || '')
        ))
      )
    )
  );
};
render(<DiffTool/>);
